# PowerShell脚本：检查Word文档结构
# 用于分析文档的节、段落、样式等信息

param(
    [string]$DocPath = "C:\Users\Administrator\AI科普画册\AI前沿知识儿童科普画册-最终版.docx"
)

Write-Host "分析文档结构..." -ForegroundColor Cyan
Write-Host "文件: $DocPath`n" -ForegroundColor Yellow

try {
    $word = New-Object -ComObject Word.Application
    $word.Visible = $false
    $doc = $word.Documents.Open($DocPath)

    Write-Host "基本信息：" -ForegroundColor Green
    Write-Host "  总页数: $($doc.ComputeStatistics(2))" -ForegroundColor Cyan
    Write-Host "  总节数: $($doc.Sections.Count)" -ForegroundColor Cyan
    Write-Host "  总段落数: $($doc.Paragraphs.Count)" -ForegroundColor Cyan

    Write-Host "`n前20个段落的内容和样式：" -ForegroundColor Green
    for ($i = 1; $i -le [Math]::Min(20, $doc.Paragraphs.Count); $i++) {
        $para = $doc.Paragraphs.Item($i)
        $text = $para.Range.Text.Trim()
        $style = $para.Style.NameLocal
        $pageNum = $para.Range.Information(3)  # wdActiveEndPageNumber

        if ($text.Length -gt 50) {
            $text = $text.Substring(0, 50) + "..."
        }

        Write-Host "  [$i] 页$pageNum | 样式: $style" -ForegroundColor Yellow
        Write-Host "      内容: $text" -ForegroundColor White
    }

    Write-Host "`n节信息：" -ForegroundColor Green
    for ($i = 1; $i -le $doc.Sections.Count; $i++) {
        $section = $doc.Sections.Item($i)
        $startPage = $section.Range.Information(3)
        Write-Host "  节 $i : 从第 $startPage 页开始" -ForegroundColor Cyan
    }

    Write-Host "`n查找标题：" -ForegroundColor Green
    $headingCount = 0
    for ($i = 1; $i -le [Math]::Min(50, $doc.Paragraphs.Count); $i++) {
        $para = $doc.Paragraphs.Item($i)
        $style = $para.Style.NameLocal

        if ($style -match "标题|Heading|Title") {
            $text = $para.Range.Text.Trim()
            $pageNum = $para.Range.Information(3)
            if ($text.Length -gt 60) {
                $text = $text.Substring(0, 60) + "..."
            }
            Write-Host "  页$pageNum | $style : $text" -ForegroundColor Yellow
            $headingCount++
        }
    }

    if ($headingCount -eq 0) {
        Write-Host "  未找到标题样式" -ForegroundColor Red
    }

    Write-Host "`n查找目录：" -ForegroundColor Green
    if ($doc.TablesOfContents.Count -gt 0) {
        Write-Host "  找到 $($doc.TablesOfContents.Count) 个目录" -ForegroundColor Cyan
        for ($i = 1; $i -le $doc.TablesOfContents.Count; $i++) {
            $toc = $doc.TablesOfContents.Item($i)
            $pageNum = $toc.Range.Information(3)
            Write-Host "  目录 $i 在第 $pageNum 页" -ForegroundColor Yellow
        }
    } else {
        Write-Host "  未找到目录对象" -ForegroundColor Red
    }

    $doc.Close($false)
    $word.Quit()

    [System.Runtime.Interopservices.Marshal]::ReleaseComObject($doc) | Out-Null
    [System.Runtime.Interopservices.Marshal]::ReleaseComObject($word) | Out-Null
    [System.GC]::Collect()
    [System.GC]::WaitForPendingFinalizers()

    Write-Host "`n分析完成" -ForegroundColor Green
}
catch {
    Write-Host "错误: $_" -ForegroundColor Red
    if ($doc) { try { $doc.Close($false) } catch {} }
    if ($word) { try { $word.Quit() } catch {} }
}

# PowerShell脚本：验证页码设置
# 检查文档的页码配置是否正确

param(
    [string]$DocPath = "C:\Users\Administrator\AI科普画册\AI前沿知识儿童科普画册-带页码版.docx"
)

Write-Host "=" * 80 -ForegroundColor Cyan
Write-Host "验证页码设置" -ForegroundColor Cyan
Write-Host "=" * 80 -ForegroundColor Cyan

if (-not (Test-Path $DocPath)) {
    Write-Host "错误：找不到文件" -ForegroundColor Red
    exit 1
}

Write-Host "`n文件: $DocPath`n" -ForegroundColor Yellow

try {
    $word = New-Object -ComObject Word.Application
    $word.Visible = $false
    $doc = $word.Documents.Open($DocPath)

    $wdHeaderFooterPrimary = 1

    Write-Host "文档基本信息：" -ForegroundColor Green
    Write-Host "  总页数: $($doc.ComputeStatistics(2))" -ForegroundColor Cyan
    Write-Host "  总节数: $($doc.Sections.Count)`n" -ForegroundColor Cyan

    Write-Host "各节页码设置：" -ForegroundColor Green
    Write-Host ("-" * 80) -ForegroundColor Gray

    for ($i = 1; $i -le $doc.Sections.Count; $i++) {
        $section = $doc.Sections.Item($i)
        $startPage = $section.Range.Information(3)  # wdActiveEndPageNumber

        Write-Host "`n节 $i (从第 $startPage 页开始)：" -ForegroundColor Yellow

        # 检查页眉页脚链接
        $footer = $section.Footers.Item($wdHeaderFooterPrimary)
        $linkToPrevious = $footer.LinkToPrevious

        Write-Host "  链接到前一节: $linkToPrevious" -ForegroundColor Cyan

        # 检查页脚内容
        $footerText = $footer.Range.Text.Trim()
        if ($footerText -eq "") {
            Write-Host "  页脚内容: (空)" -ForegroundColor Cyan
        } else {
            Write-Host "  页脚内容: $footerText" -ForegroundColor Cyan
        }

        # 检查页码设置
        if ($footer.PageNumbers.Count -gt 0) {
            $pageNumbers = $footer.PageNumbers.Item(1)
            Write-Host "  页码数量: $($footer.PageNumbers.Count)" -ForegroundColor Cyan
            Write-Host "  重新开始编号: $($pageNumbers.RestartNumberingAtSection)" -ForegroundColor Cyan
            Write-Host "  起始页码: $($pageNumbers.StartingNumber)" -ForegroundColor Cyan
            Write-Host "  页码样式: $($pageNumbers.NumberStyle)" -ForegroundColor Cyan

            # 解释页码样式
            $styleText = switch ($pageNumbers.NumberStyle) {
                0 { "阿拉伯数字 (1, 2, 3...)" }
                4 { "小写罗马数字 (i, ii, iii...)" }
                5 { "大写罗马数字 (I, II, III...)" }
                default { "其他样式 ($($pageNumbers.NumberStyle))" }
            }
            Write-Host "  样式说明: $styleText" -ForegroundColor Green
        } else {
            Write-Host "  页码: 无" -ForegroundColor Cyan
        }

        # 检查DifferentFirstPageHeaderFooter
        if ($i -eq 1) {
            Write-Host "  首页不同: $($section.PageSetup.DifferentFirstPageHeaderFooter)" -ForegroundColor Cyan
        }
    }

    Write-Host "`n" + ("-" * 80) -ForegroundColor Gray
    Write-Host "`n验证结果：" -ForegroundColor Green

    # 验证逻辑
    $allGood = $true

    # 检查节1（封面）
    if ($doc.Sections.Count -ge 1) {
        $s1 = $doc.Sections.Item(1)
        if ($s1.PageSetup.DifferentFirstPageHeaderFooter) {
            Write-Host "  ✓ 节1（封面）：首页不同设置正确" -ForegroundColor Green
        } else {
            Write-Host "  ✗ 节1（封面）：首页不同设置错误" -ForegroundColor Red
            $allGood = $false
        }
    }

    # 检查节2（扉页）
    if ($doc.Sections.Count -ge 2) {
        $s2 = $doc.Sections.Item(2)
        $f2 = $s2.Footers.Item($wdHeaderFooterPrimary)
        if (-not $f2.LinkToPrevious -and $f2.PageNumbers.Count -eq 0) {
            Write-Host "  ✓ 节2（扉页）：无页码设置正确" -ForegroundColor Green
        } else {
            Write-Host "  ✗ 节2（扉页）：页码设置可能有问题" -ForegroundColor Yellow
        }
    }

    # 检查节3（目录）
    if ($doc.Sections.Count -ge 3) {
        $s3 = $doc.Sections.Item(3)
        $f3 = $s3.Footers.Item($wdHeaderFooterPrimary)
        if (-not $f3.LinkToPrevious -and $f3.PageNumbers.Count -gt 0) {
            $pn3 = $f3.PageNumbers.Item(1)
            if ($pn3.NumberStyle -eq 4 -and $pn3.RestartNumberingAtSection -and $pn3.StartingNumber -eq 1) {
                Write-Host "  ✓ 节3（目录）：罗马数字页码设置正确" -ForegroundColor Green
            } else {
                Write-Host "  ✗ 节3（目录）：页码设置不完全正确" -ForegroundColor Yellow
            }
        } else {
            Write-Host "  ✗ 节3（目录）：页码设置错误" -ForegroundColor Red
            $allGood = $false
        }
    }

    # 检查节4（正文）
    if ($doc.Sections.Count -ge 4) {
        $s4 = $doc.Sections.Item(4)
        $f4 = $s4.Footers.Item($wdHeaderFooterPrimary)
        if (-not $f4.LinkToPrevious -and $f4.PageNumbers.Count -gt 0) {
            $pn4 = $f4.PageNumbers.Item(1)
            if ($pn4.NumberStyle -eq 0 -and $pn4.RestartNumberingAtSection -and $pn4.StartingNumber -eq 1) {
                Write-Host "  ✓ 节4（正文）：阿拉伯数字页码设置正确" -ForegroundColor Green
            } else {
                Write-Host "  ✗ 节4（正文）：页码设置不完全正确" -ForegroundColor Yellow
            }
        } else {
            Write-Host "  ✗ 节4（正文）：页码设置错误" -ForegroundColor Red
            $allGood = $false
        }
    }

    Write-Host "`n" + ("=" * 80) -ForegroundColor Cyan
    if ($allGood) {
        Write-Host "验证通过！页码系统设置正确。" -ForegroundColor Green
    } else {
        Write-Host "验证发现问题，请检查上述标记为 ✗ 的项目。" -ForegroundColor Yellow
    }
    Write-Host ("=" * 80) -ForegroundColor Cyan

    $doc.Close($false)
    $word.Quit()

    [System.Runtime.Interopservices.Marshal]::ReleaseComObject($doc) | Out-Null
    [System.Runtime.Interopservices.Marshal]::ReleaseComObject($word) | Out-Null
    [System.GC]::Collect()
    [System.GC]::WaitForPendingFinalizers()
}
catch {
    Write-Host "`n错误: $_" -ForegroundColor Red
    Write-Host $_.Exception.Message -ForegroundColor Red

    if ($doc) { try { $doc.Close($false) } catch {} }
    if ($word) { try { $word.Quit() } catch {} }
    exit 1
}
